from click.testing import CliRunner
import contextlib

@contextlib.contextmanager
def res():
    yield 'r'

@click.group(context_settings={'max_resources': 2})
@click.pass_context
def cli(ctx):
    ctx.with_resource(res())

@cli.command()
@click.pass_context
def sub(ctx):
    ctx.with_resource(res())
    try:
        ctx.with_resource(res())
        click.echo('FAIL')
    except RuntimeError as e:
        click.echo(f'OK: {e}')

runner = CliRunner()
result = runner.invoke(cli, ['sub'])
print(result.output)
